func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Set up timeout protection (5 seconds)
	timeout := 5 * time.Second
	halted := make(chan struct{})

	go func() {
		time.Sleep(timeout)
		close(halted)
	}()

	vm.SetInterruptHandler(func() {
		select {
		case <-halted:
			panic(goja.NewGoError(errors.New("script execution timeout")))
		default:
		}
	})

	// Inject the order object as a global variable
	if err := vm.Set("order", order); err != nil {
		return 0.0, fmt.Errorf("failed to set order object: %w", err)
	}

	// Inject all order fields as global variables in the VM (for backward compatibility)
	for key, value := range order {
		if err := vm.Set(key, value); err != nil {
			return 0.0, fmt.Errorf("failed to set order field %s: %w", key, err)
		}
	}

	// Execute the script
	result, err := vm.RunString(script)
	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
