	ctx, cancel := context.WithTimeout(context.Background(), 100*time.Millisecond)
	defer cancel()

	vm := goja.New()

	// Set up interrupt channel for timeout handling
	go func() {
		<-ctx.Done()
		vm.Interrupt("execution timeout")
	}()

	// Pass order as a single object instead of individual globals
	// This prevents namespace pollution and potential conflicts with built-in objects
	orderObj := vm.NewObject()
	for key, value := range order {
		orderObj.Set(key, value)
	}
	vm.Set("order", orderObj)

	// Execute the script
	result, err := vm.RunString(script)
	if err != nil {
		// Check if it's a timeout error
		if ctx.Err() == context.DeadlineExceeded {
			return 0.0, fmt.Errorf("script execution timeout")
		}
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Convert result to float64
	var discount float64
	switch v := result.Export().(type) {
	case float64:
		discount = v
	case int:
		discount = float64(v)
	case int32:
		discount = float64(v)
	case int64:
		discount = float64(v)
	case float32:
		discount = float64(v)
	default:
		return 0.0, fmt.Errorf("script must return a number, got %T", result.Export())
	}

	// Validate discount range (non-negative)
	if discount < 0 {
		return 0.0, fmt.Errorf("discount cannot be negative: %f", discount)
	}

	// Validate discount doesn't exceed order total (prevent negative final price)
	if orderTotal, ok := order["total"].(float64); ok {
		if discount > orderTotal {
			return 0.0, fmt.Errorf("discount cannot exceed order total: %f > %f", discount, orderTotal)
		}
	}

	return discount, nil
}

func main() {
	// Example usage
	order := map[string]interface{}{
		"total":       100.0,
		"memberLevel": "gold",
		"itemCount":   5,
	}

	script := `
		if (order.memberLevel === "gold") {
			order.total * 0.1;
		} else {
			0;
		}
	`

	discount, err := CalculateDiscount(script, order)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Discount: %f\n", discount)
}

